import { Anthropic } from '@anthropic-ai/sdk';
import { Vex } from 'vex-sdk';

const anthropic = new Anthropic({ apiKey: 'your-key' });
const vex = new Vex({ apiKey: 'your-vex-key' });

async function verifyToolUse() {
  const message = await anthropic.messages.create({
    model: 'claude-3-5-sonnet-20240620',
    max_tokens: 1024,
    tools: [{ type: 'function', name: 'query_federal_db', input_schema: {...} }],
    messages: [{ role: 'user', content: 'Check security clearance status' }]
  });

  const verification = await vex.verify({
    agentInputs: message.input,
    agentOutputs: message.content,
    policy: 'fedramp-tool-verification',
    metadata: { sensitivity: 'critical', agency: 'DOD' }
  });

  return verification.status === 'pass' ? message : null;
}
